<script lang="tsx" setup>
import { Signature } from '@/src/http'
import Editor from './SettingsTextEditor.vue'

const user = useUser()
const snippet = ref(user.signature)

const { isLoading, refresh: uploadSignature } = usePromise(undefined, async (file?: File) => {
  file ??= await chooseFile()

  if (!file)
    return

  const result = await Signature.upload(file)
  user.signature = result.signature
  snippet.value = result.signature
})

async function onSnippetUpdate(code: string) {
  // Sanitize the code
  code = Signature.sanitize(code) ?? ''

  const file = new File([code], 'signature.html', { type: 'text/html' })
  await Signature.upload(file)

  // Update local store
  snippet.value = code
}

const { isOverDropZone } = useDropZone(document.body, {
  dataTypes: ['image/png', 'image/jpeg', 'image/gif', 'text/html'],
  onDrop(files) {
    const [file] = files ?? []

    if (file)
      uploadSignature(file)
  }
})
</script>

<template>
  <section>
    <h5 class="mb-3 text-13px text-neutral/80">
      Add your personal signature at the end of all emails
    </h5>

    <div class="p-4 gap-4 grow flex flex-col relative rounded-md border-1 border-neutral/8 overflow-hidden">
      <Tabs
        label-wrapper-class="gap-4 flex items-center"
        label-class="text-xs text-neutral/50"
        active-label-class="!text-neutral"
        content-class="grow"
      >
        <div
          label="File Upload"
          class="p-6 flex-center rounded-md border-1 border-dashed border-neutral/12"
          :class="{ 'bg-primary/2 border-primary': isOverDropZone }"
          @click="uploadSignature()"
        >
          <h6 class="text-sm text-neutral/70">
            Drag image or html file here
          </h6>
        </div>

        <Editor
          v-model="user.signature"
          v-model:session="snippet"
          label="HTML Editor"
          class="p-3"
          placeholder="Enter your signature here"
          @save="onSnippetUpdate"
        />
      </Tabs>

      <!-- Preview -->
      <div v-if="snippet" class="max-h-200px overflow-y-auto">
        <h6 class="mb-2 text-xs">
          Preview
        </h6>

        <div v-html="Signature.sanitize(snippet, { collapseLines: true })" />
      </div>

      <!-- Loader -->
      <Transition name="fade" mode="out-in">
        <div v-if="isLoading" class="absolute inset-0 flex-center bg-white/50 text-primary backdrop-blur-4">
          <Spinner />
        </div>
      </Transition>
    </div>
  </section>
</template>
